  1→#!/usr/bin/env node
  2→
  3→/**
  4→ * Belt CLI
  5→ *
  6→ * Main entry point for the global 'belt' command.
  7→ *
  8→ * Commands:
  9→ *   belt setup [dir]      - Setup AgentRC in project
 10→ *   belt hook             - Hook runner for Claude Code
 11→ *   belt init [dir]       - Initialize new monorepo with harness
 12→ *   belt brainstorm [dir] - Run AI brainstorming session
 13→ */
 14→
 15→import { readFileSync } from 'fs';
 16→import { dirname, resolve } from 'path';
 17→import { fileURLToPath } from 'url';
 18→import { brainstorm, parseBrainstormArgs } from './commands/brainstorm';
 19→import { hook } from './commands/hook';
 20→import { init } from './commands/init';
 21→import { setup } from './commands/setup';
 22→
 23→const __filename = fileURLToPath(import.meta.url);
 24→const __dirname = dirname(__filename);
 25→
 26→function getVersion(): string {
 27→  try {
 28→    const pkgPath = resolve(__dirname, '..', 'package.json');
 29→    const pkg = JSON.parse(readFileSync(pkgPath, 'utf-8'));
 30→    return pkg.version || '0.0.0';
 31→  } catch {
 32→    return '0.0.0';
 33→  }
 34→}
 35→
 36→function showHelp(): void {
 37→  console.log(`
 38→belt - Belt CLI for AI-powered development
 39→
 40→Usage:
 41→  belt <command> [options]
 42→
 43→Commands:
 44→  setup [directory]      Setup AgentRC in the specified directory (default: current)
 45→  hook                   Hook runner for Claude Code (reads from stdin)
 46→  init [directory]       Initialize new monorepo with full harness
 47→  brainstorm [directory] Run AI brainstorming session (Self-MoA + Self-Refine)
 48→
 49→Options:
 50→  --help, -h         Show this help message
 51→  --version, -v      Show version number
 52→
 53→Brainstorm Options:
 54→  --non-interactive, -n  Run without interactive prompts
 55→  --name <name>          Project name
 56→  --description <desc>   Project description
 57→  --domain <domain>      Project domain
 58→  --goal <goal>          Project goal (can be repeated)
 59→  --ollama-host <url>    Ollama API URL (default: http://localhost:11434)
 60→
 61→Examples:
 62→  belt setup                   # Setup in current directory
 63→  belt setup ./my-project      # Setup in ./my-project
 64→  belt init ./new-project      # Create new monorepo with harness
 65→  belt hook                    # Run as Claude Code hook (piped input)
 66→  belt brainstorm              # Run interactive brainstorming
 67→  belt brainstorm -n --name "MyApp" --description "A cool app"
 68→
 69→Philosophy:
 70→  "Better spend 3 days creating a robust setup than weeks recreating
 71→   projects because the harness starts hallucinating as the project grows."
 72→
 73→For more info: https://github.com/antoniopresto/belt
 74→`);
 75→}
 76→
 77→async function main(): Promise<void> {
 78→  const args = process.argv.slice(2);
 79→  const command = args[0];
 80→
 81→  if (!command || command === '--help' || command === '-h') {
 82→    showHelp();
 83→    process.exit(0);
 84→  }
 85→
 86→  if (command === '--version' || command === '-v') {
 87→    console.log(`belt v${getVersion()}`);
 88→    process.exit(0);
 89→  }
 90→
 91→  switch (command) {
 92→    case 'setup': {
 93→      const targetDir = args[1] || process.cwd();
 94→      await setup(targetDir);
 95→      break;
 96→    }
 97→
 98→    case 'hook': {
 99→      await hook();
100→      break;
101→    }
102→
103→    case 'init': {
104→      const targetDir = args[1] || process.cwd();
105→      await init(targetDir);
106→      break;
107→    }
108→
109→    case 'brainstorm': {
110→      const parsed = parseBrainstormArgs(args.slice(1));
111→      await brainstorm(parsed.projectDir, parsed.context, parsed.options);
112→      break;
113→    }
114→
115→    default:
116→      console.error(`Unknown command: ${command}`);
117→      console.error('Run "belt --help" for usage information.');
118→      process.exit(1);
119→  }
120→}
121→
122→main().catch(err => {
123→  console.error('Error:', err.message || err);
124→  process.exit(1);
125→});
