  1→import {
  2→	existsSync,
  3→	readFileSync,
  4→	statSync,
  5→	unlinkSync,
  6→	writeFileSync,
  7→} from "node:fs";
  8→import robot from "@jitsi/robotjs";
  9→import { ensureConfigDir, LOG_FILE, PID_FILE } from "./paths.js";
 10→import { incrementJiggle, incrementSkipped, markStarted } from "./stats.js";
 11→import type { Config } from "./types.js";
 12→
 13→const MAX_LOG_SIZE_BYTES = 5 * 1024 * 1024; // 5MB
 14→
 15→export function getRandomInterval(
 16→	baseMs: number,
 17→	variancePercent = 0.3,
 18→): number {
 19→	const variance = baseMs * variancePercent;
 20→	return Math.round(baseMs + (Math.random() * 2 - 1) * variance);
 21→}
 22→
 23→export function writePidFile(): void {
 24→	ensureConfigDir();
 25→	writeFileSync(PID_FILE, String(process.pid), "utf-8");
 26→}
 27→
 28→export function removePidFile(): void {
 29→	if (existsSync(PID_FILE)) {
 30→		unlinkSync(PID_FILE);
 31→	}
 32→}
 33→
 34→export function readPidFile(): number | null {
 35→	if (!existsSync(PID_FILE)) {
 36→		return null;
 37→	}
 38→	try {
 39→		const content = readFileSync(PID_FILE, "utf-8");
 40→		return parseInt(content.trim(), 10);
 41→	} catch {
 42→		return null;
 43→	}
 44→}
 45→
 46→export function isProcessRunning(pid: number): boolean {
 47→	try {
 48→		process.kill(pid, 0);
 49→		return true;
 50→	} catch {
 51→		return false;
 52→	}
 53→}
 54→
 55→export function isDaemonRunning(): {
 56→	running: boolean;
 57→	pid: number | null;
 58→} {
 59→	const pid = readPidFile();
 60→	if (pid === null) {
 61→		return {
 62→			running: false,
 63→			pid: null,
 64→		};
 65→	}
 66→	const running = isProcessRunning(pid);
 67→	if (!running) {
 68→		removePidFile();
 69→	}
 70→	return {
 71→		running,
 72→		pid: running ? pid : null,
 73→	};
 74→}
 75→
 76→export function getLogFile(): string {
 77→	return LOG_FILE;
 78→}
 79→
 80→export function rotateLogIfNeeded(): void {
 81→	try {
 82→		if (!existsSync(LOG_FILE)) return;
 83→
 84→		const stats = statSync(LOG_FILE);
 85→		if (stats.size > MAX_LOG_SIZE_BYTES) {
 86→			// Keep last 20% of the file
 87→			const keepBytes = Math.floor(MAX_LOG_SIZE_BYTES * 0.2);
 88→			const content = readFileSync(LOG_FILE, "utf-8");
 89→			const truncated = content.slice(-keepBytes);
 90→			writeFileSync(
 91→				LOG_FILE,
 92→				`[LOG ROTATED - kept last ${Math.round(keepBytes / 1024)}KB]\n${truncated}`,
 93→			);
 94→		}
 95→	} catch {
 96→		// Ignore rotation errors
 97→	}
 98→}
 99→
100→export class ComplianceDaemon {
101→	private intervalId: NodeJS.Timeout | null = null;
102→	private lastPos: {
103→		x: number;
104→		y: number;
105→	} | null = null;
106→	private lastActivityTime: number = Date.now();
107→	private logFile: string;
108→	private tickCount = 0;
109→
110→	constructor(private config: Config) {
111→		this.logFile = LOG_FILE;
112→	}
113→
114→	start(): void {
115→		writePidFile();
116→		markStarted();
117→
118→		this.log("Starting Compliance Daemon...");
119→		this.log(
120→			`Config: interval=${this.config.intervalMs}ms, pixels=${this.config.movementPx}, mode=${this.config.mode}`,
121→		);
122→		this.log(`PID: ${process.pid}`);
123→		this.log(`Log file: ${this.logFile}`);
124→
125→		this.scheduleNext();
126→
127→		process.on("SIGINT", () => this.shutdown());
128→		process.on("SIGTERM", () => this.shutdown());
129→	}
130→
131→	private scheduleNext(): void {
132→		const interval = getRandomInterval(this.config.intervalMs);
133→		this.log(`Next tick in ${interval}ms`);
134→		this.intervalId = setTimeout(() => {
135→			this.tick();
136→			this.scheduleNext();
137→		}, interval);
138→	}
139→
140→	private tick(): void {
141→		this.tickCount++;
142→
143→		// Check log rotation every 100 ticks
144→		if (this.tickCount % 100 === 0) {
145→			rotateLogIfNeeded();
146→		}
147→
148→		if (!this.shouldActivate()) {
149→			this.log("User active, skipping...");
150→			incrementSkipped();
151→			return;
152→		}
153→
154→		switch (this.config.mode) {
155→			case "mouse":
156→				this.jiggleMouse();
157→				break;
158→			case "keyboard":
159→				this.jiggleKeyboard();
160→				break;
161→			case "both":
162→				Math.random() > 0.5 ? this.jiggleMouse() : this.jiggleKeyboard();
163→				break;
164→		}
165→	}
166→
167→	private jiggleMouse(): void {
168→		try {
169→			const { x, y } = robot.getMousePos();
170→			const angle = Math.random() * Math.PI * 2;
171→			const radius = this.config.movementPx;
172→
173→			const newX = Math.round(x + Math.cos(angle) * radius);
174→			const newY = Math.round(y + Math.sin(angle) * radius);
175→
176→			robot.moveMouse(newX, newY);
177→
178→			setTimeout(
179→				() => {
180→					robot.moveMouse(x, y);
181→				},
182→				30 + Math.random() * 50,
183→			);
184→
185→			this.log(`Mouse jiggle: (${x},${y}) → (${newX},${newY}) → (${x},${y})`);
186→			incrementJiggle("mouse");
187→		} catch (err) {
188→			this.logError("Mouse jiggle failed:", err);
189→			this.logError("Make sure Accessibility permission is granted");
190→		}
191→	}
192→
193→	private jiggleKeyboard(): void {
194→		try {
195→			robot.keyToggle("shift", "down");
196→			robot.keyToggle("shift", "up");
197→			this.log("Keyboard jiggle: Shift press/release");
198→			incrementJiggle("keyboard");
199→		} catch (err) {
200→			this.logError("Keyboard jiggle failed:", err);
201→		}
202→	}
203→
204→	private shouldActivate(): boolean {
205→		const currentPos = robot.getMousePos();
206→
207→		if (
208→			this.lastPos &&
209→			(currentPos.x !== this.lastPos.x || currentPos.y !== this.lastPos.y)
210→		) {
211→			this.lastActivityTime = Date.now();
212→		}
213→
214→		this.lastPos = currentPos;
215→
216→		const idleTime = Date.now() - this.lastActivityTime;
217→		return idleTime > this.config.idleThresholdMs;
218→	}
219→
220→	private log(message: string): void {
221→		if (this.config.verbose) {
222→			const timestamp = new Date().toISOString();
223→			const line = `[${timestamp}] ${message}`;
224→			console.log(line);
225→		}
226→	}
227→
228→	private logError(message: string, err?: unknown): void {
229→		const timestamp = new Date().toISOString();
230→		const errorMsg = err instanceof Error ? err.message : String(err);
231→		console.error(
232→			`[${timestamp}] [ERROR] ${message}`,
233→			errorMsg ? errorMsg : "",
234→		);
235→	}
236→
237→	private shutdown(): void {
238→		this.log("Shutting down...");
239→		if (this.intervalId) {
240→			clearTimeout(this.intervalId);
241→		}
242→		removePidFile();
243→		process.exit(0);
244→	}
245→}
