  1→import { existsSync, readFileSync, writeFileSync } from "node:fs";
  2→import { CONFIG_FILE, ensureConfigDir } from "./paths.js";
  3→import {
  4→	type Config,
  5→	DEFAULT_CONFIG,
  6→	MAX_PIXELS,
  7→	MIN_INTERVAL_MS,
  8→	MIN_THRESHOLD_MS,
  9→	type Mode,
 10→	VALID_MODES,
 11→	type ValidationResult,
 12→} from "./types.js";
 13→
 14→export function loadConfig(): Config {
 15→	ensureConfigDir();
 16→
 17→	if (!existsSync(CONFIG_FILE)) {
 18→		return { ...DEFAULT_CONFIG };
 19→	}
 20→
 21→	try {
 22→		const content = readFileSync(CONFIG_FILE, "utf-8");
 23→		const parsed = JSON.parse(content) as Partial<Config>;
 24→		return {
 25→			...DEFAULT_CONFIG,
 26→			...parsed,
 27→		};
 28→	} catch {
 29→		return { ...DEFAULT_CONFIG };
 30→	}
 31→}
 32→
 33→export function saveConfig(config: Config): void {
 34→	ensureConfigDir();
 35→	writeFileSync(CONFIG_FILE, JSON.stringify(config, null, 2), "utf-8");
 36→}
 37→
 38→export function getConfigValue<K extends keyof Config>(key: K): Config[K] {
 39→	const config = loadConfig();
 40→	return config[key];
 41→}
 42→
 43→export function setConfigValue<K extends keyof Config>(
 44→	key: K,
 45→	value: Config[K],
 46→): ValidationResult {
 47→	const validation = validateConfigValue(key, value);
 48→	if (!validation.valid) {
 49→		return validation;
 50→	}
 51→
 52→	const config = loadConfig();
 53→	config[key] = value;
 54→	saveConfig(config);
 55→	return { valid: true };
 56→}
 57→
 58→export function resetConfig(): void {
 59→	saveConfig({ ...DEFAULT_CONFIG });
 60→}
 61→
 62→export function getDefaults(): Config {
 63→	return { ...DEFAULT_CONFIG };
 64→}
 65→
 66→export function validateInterval(value: number): ValidationResult {
 67→	if (Number.isNaN(value) || value < MIN_INTERVAL_MS) {
 68→		return {
 69→			valid: false,
 70→			error: `Interval must be >= ${MIN_INTERVAL_MS}ms`,
 71→		};
 72→	}
 73→	return { valid: true };
 74→}
 75→
 76→export function validatePixels(value: number): ValidationResult {
 77→	if (Number.isNaN(value) || value < 1 || value > MAX_PIXELS) {
 78→		return {
 79→			valid: false,
 80→			error: `Pixels must be between 1 and ${MAX_PIXELS}`,
 81→		};
 82→	}
 83→	return { valid: true };
 84→}
 85→
 86→export function validateThreshold(value: number): ValidationResult {
 87→	if (Number.isNaN(value) || value < MIN_THRESHOLD_MS) {
 88→		return {
 89→			valid: false,
 90→			error: `Threshold must be >= ${MIN_THRESHOLD_MS}ms`,
 91→		};
 92→	}
 93→	return { valid: true };
 94→}
 95→
 96→export function validateMode(value: string): ValidationResult {
 97→	if (!VALID_MODES.includes(value as Mode)) {
 98→		return {
 99→			valid: false,
100→			error: `Invalid mode "${value}". Valid options: ${VALID_MODES.join(", ")}`,
101→		};
102→	}
103→	return { valid: true };
104→}
105→
106→export function validateConfigValue<K extends keyof Config>(
107→	key: K,
108→	value: Config[K],
109→): ValidationResult {
110→	switch (key) {
111→		case "intervalMs":
112→			return validateInterval(value as number);
113→		case "movementPx":
114→			return validatePixels(value as number);
115→		case "idleThresholdMs":
116→			return validateThreshold(value as number);
117→		case "mode":
118→			return validateMode(value as string);
119→		case "verbose":
120→			if (typeof value !== "boolean") {
121→				return {
122→					valid: false,
123→					error: "Verbose must be true or false",
124→				};
125→			}
126→			return { valid: true };
127→		default:
128→			return {
129→				valid: false,
130→				error: `Unknown config key: ${key}`,
131→			};
132→	}
133→}
134→
135→export function parseConfigValue(
136→	key: keyof Config,
137→	value: string,
138→): {
139→	parsed: Config[keyof Config] | null;
140→	error?: string;
141→} {
142→	switch (key) {
143→		case "intervalMs":
144→		case "movementPx":
145→		case "idleThresholdMs": {
146→			const num = parseInt(value, 10);
147→			if (Number.isNaN(num)) {
148→				return {
149→					parsed: null,
150→					error: `Invalid number: ${value}`,
151→				};
152→			}
153→			return { parsed: num };
154→		}
155→		case "mode":
156→			return { parsed: value as Mode };
157→		case "verbose":
158→			if (value === "true" || value === "1") return { parsed: true };
159→			if (value === "false" || value === "0") return { parsed: false };
160→			return {
161→				parsed: null,
162→				error: "Verbose must be true or false",
163→			};
164→		default:
165→			return {
166→				parsed: null,
167→				error: `Unknown key: ${key}`,
168→			};
169→	}
170→}
171→
172→export function formatConfig(config: Config): string {
173→	const lines = [
174→		"┌─────────────────────────────────────┐",
175→		"│         Current Configuration       │",
176→		"├─────────────────────────────────────┤",
177→		`│  intervalMs      │ ${String(config.intervalMs).padEnd(16)} │`,
178→		`│  movementPx      │ ${String(config.movementPx).padEnd(16)} │`,
179→		`│  idleThresholdMs │ ${String(config.idleThresholdMs).padEnd(16)} │`,
180→		`│  mode            │ ${config.mode.padEnd(16)} │`,
181→		`│  verbose         │ ${String(config.verbose).padEnd(16)} │`,
182→		"└─────────────────────────────────────┘",
183→	];
184→	return lines.join("\n");
185→}
