 59→export function formatDuration(ms: number): string {
 60→	const seconds = Math.floor(ms / 1000);
 61→	const minutes = Math.floor(seconds / 60);
 62→	const hours = Math.floor(minutes / 60);
 63→	const days = Math.floor(hours / 24);
 64→
 65→	if (days > 0) {
 66→		return `${days}d ${hours % 24}h ${minutes % 60}m`;
 67→	}
 68→	if (hours > 0) {
 69→		return `${hours}h ${minutes % 60}m ${seconds % 60}s`;
 70→	}
 71→	if (minutes > 0) {
 72→		return `${minutes}m ${seconds % 60}s`;
 73→	}
 74→	return `${seconds}s`;
 75→}
 76→
 77→export function formatStats(stats: Stats): string {
 78→	let uptime = "Not running";
 79→	if (stats.startedAt) {
 80→		const startDate = new Date(stats.startedAt);
 81→		const now = new Date();
 82→		uptime = formatDuration(now.getTime() - startDate.getTime());
 83→	}
 84→
 85→	let lastJiggle = "Never";
 86→	if (stats.lastJiggleAt) {
 87→		const lastDate = new Date(stats.lastJiggleAt);
 88→		const now = new Date();
 89→		const ago = formatDuration(now.getTime() - lastDate.getTime());
 90→		lastJiggle = `${ago} ago`;
 91→	}
 92→
 93→	const lines = [
 94→		"┌─────────────────────────────────────┐",
 95→		"│            Statistics               │",
 96→		"├─────────────────────────────────────┤",
 97→		`│  Uptime          │ ${uptime.padEnd(16)} │`,
 98→		`│  Total jiggles   │ ${String(stats.totalJiggles).padEnd(16)} │`,
 99→		`│  Mouse jiggles   │ ${String(stats.mouseJiggles).padEnd(16)} │`,
100→		`│  Keyboard jiggles│ ${String(stats.keyboardJiggles).padEnd(16)} │`,
101→		`│  Skipped (active)│ ${String(stats.skippedDueToActivity).padEnd(16)} │`,
102→		`│  Last jiggle     │ ${lastJiggle.padEnd(16)} │`,
103→		"└─────────────────────────────────────┘",
104→	];
105→	return lines.join("\n");
106→}
