  1→#!/usr/bin/env node
  2→
  3→/**
  4→ * belt-setup CLI
  5→ *
  6→ * Quick setup for Belt AI tools in any project.
  7→ * Installs bun, @belt/cli globally, and creates .belt/ structure.
  8→ *
  9→ * Usage:
 10→ *   npx belt-setup              # Setup in current directory
 11→ *   npx belt-setup ./myproj     # Setup in specific directory
 12→ *   npx belt-setup --help       # Show help
 13→ */
 14→
 15→import { execSync } from 'child_process';
 16→import { readFileSync } from 'fs';
 17→import { dirname, resolve } from 'path';
 18→import { fileURLToPath } from 'url';
 19→
 20→const __filename = fileURLToPath(import.meta.url);
 21→const __dirname = dirname(__filename);
 22→
 23→function getVersion(): string {
 24→  try {
 25→    const pkgPath = resolve(__dirname, '..', 'package.json');
 26→    const pkg = JSON.parse(readFileSync(pkgPath, 'utf-8'));
 27→    return pkg.version || '0.0.0';
 28→  } catch {
 29→    return '0.0.0';
 30→  }
 31→}
 32→
 33→function showHelp(): void {
 34→  console.log(`
 35→belt-setup - Quick Setup for Belt AI Tools
 36→
 37→Usage:
 38→  belt-setup [directory]  Setup Belt in the specified directory (default: current)
 39→
 40→Options:
 41→  --help, -h         Show this help message
 42→  --version, -v      Show version number
 43→
 44→Examples:
 45→  npx belt-setup              # Setup in current directory
 46→  npx belt-setup ./my-project # Setup in ./my-project
 47→
 48→What it does:
 49→  1. Checks/installs bun if not present
 50→  2. Installs @belt/cli globally
 51→  3. Creates .belt/ directory structure
 52→  4. Creates .claude/ for Claude Code hooks
 53→  5. Creates .agentrc.ts template
 54→
 55→After setup, use the global 'belt' command:
 56→  belt setup    # Equivalent to npx belt-setup
 57→  belt hook     # Hook runner for Claude Code
 58→  belt init     # Initialize new monorepo with full harness
 59→
 60→For more info: https://github.com/antoniopresto/belt
 61→`);
 62→}
 63→
 64→function checkBun(): boolean {
 65→  try {
 66→    const result = execSync('which bun', {
 67→      encoding: 'utf-8',
 68→      stdio: 'pipe',
 69→    });
 70→    return result.trim().length > 0;
 71→  } catch {
 72→    return false;
 73→  }
 74→}
 75→
 76→async function installBun(): Promise<void> {
 77→  console.log('📦 Installing bun...');
 78→  try {
 79→    execSync('curl -fsSL https://bun.sh/install | bash', {
 80→      stdio: 'inherit',
 81→      shell: '/bin/bash',
 82→    });
 83→    console.log('✅ Bun installed successfully\n');
 84→  } catch {
 85→    console.error('⚠️  Failed to install bun automatically');
 86→    console.error('   Please install manually: https://bun.sh\n');
 87→  }
 88→}
 89→
 90→function checkBeltCli(): boolean {
 91→  try {
 92→    execSync('which belt', {
 93→      encoding: 'utf-8',
 94→      stdio: 'pipe',
 95→    });
 96→    return true;
 97→  } catch {
 98→    return false;
 99→  }
100→}
101→
102→async function installBeltCli(): Promise<void> {
103→  console.log('📦 Installing @belt/cli globally...');
104→  try {
105→    execSync('bun install -g @belt/cli', { stdio: 'inherit' });
106→    console.log('✅ @belt/cli installed globally\n');
107→  } catch {
108→    console.error('⚠️  Failed to install @belt/cli globally');
109→    console.error('   You can still use: bunx @belt/cli <command>\n');
110→  }
111→}
112→
113→async function main(): Promise<void> {
114→  const args = process.argv.slice(2);
115→  const command = args[0];
116→
117→  if (command === '--help' || command === '-h') {
118→    showHelp();
119→    process.exit(0);
120→  }
121→
122→  if (command === '--version' || command === '-v') {
123→    console.log(`belt-setup v${getVersion()}`);
124→    process.exit(0);
125→  }
126→
127→  // Default behavior: run setup
128→  const targetDir =
129→    command && !command.startsWith('-') ? command : process.cwd();
130→
131→  console.log('\n🔧 belt-setup');
132→  console.log('   Setting up Belt AI tools...\n');
133→
134→  // Step 1: Check/install bun
135→  if (checkBun()) {
136→    console.log('✅ Bun is installed');
137→  } else {
138→    console.log('⚠️  Bun is not installed');
139→    await installBun();
140→  }
141→
142→  // Step 2: Check/install @belt/cli globally
143→  if (checkBeltCli()) {
144→    console.log('✅ @belt/cli is installed globally');
145→  } else {
146→    await installBeltCli();
147→  }
148→
149→  // Step 3: Run the setup command from @belt/cli
150→  console.log('\n📁 Running belt setup...\n');
151→
152→  try {
153→    // Import and run setup from @belt/cli
154→    const { setup } = await import('@belt/cli');
155→    await setup(targetDir);
156→  } catch {
157→    // Fallback to @belt/ai setup if @belt/cli not available
158→    console.log('ℹ️  Using fallback setup...');
159→    const { setup } = await import('@belt/ai/setup');
160→    setup(targetDir);
161→  }
162→
163→  console.log('\n✨ belt-setup complete!');
164→  console.log('\nYou can now use the global "belt" command:');
165→  console.log('  belt setup    # Equivalent to npx belt-setup');
166→  console.log('  belt hook     # Hook runner for Claude Code');
167→  console.log('  belt init     # Initialize new monorepo with full harness\n');
168→}
169→
170→main().catch(err => {
171→  console.error('Setup failed:', err);
172→  process.exit(1);
173→});
