  1→/**
  2→ * Brainstorm Command
  3→ *
  4→ * Runs the AI-powered brainstorming session using local LLMs.
  5→ * Implements Self-MoA, Self-Refine, and LLM-as-Judge patterns.
  6→ */
  7→
  8→import { existsSync } from 'fs';
  9→import { resolve } from 'path';
 10→import {
 11→  createBrainstormSession,
 12→  type BrainstormSessionConfig,
 13→  type FeatureBacklog,
 14→  type ProjectContext,
 15→} from '../harness/brainstorm';
 16→import {
 17→  createFeaturesFile,
 18→  createProgressFile,
 19→  initBeltDirectory,
 20→} from '../harness/persistence/progress';
 21→
 22→export interface BrainstormOptions {
 23→  interactive?: boolean;
 24→  ollamaHost?: string;
 25→  skipPrerequisites?: boolean;
 26→}
 27→
 28→/**
 29→ * Run the brainstorming command
 30→ */
 31→export async function brainstorm(
 32→  projectDir: string,
 33→  providedContext?: Partial<ProjectContext>,
 34→  options: BrainstormOptions = {},
 35→): Promise<void> {
 36→  const resolvedDir = resolve(projectDir);
 37→
 38→  console.log('\n🧠 Belt Brainstorming Session\n');
 39→  console.log('Using Self-MoA + Self-Refine + LLM-as-Judge patterns');
 40→  console.log('─'.repeat(50));
 41→
 42→  // Ensure .belt directory exists
 43→  if (!existsSync(resolve(resolvedDir, '.belt'))) {
 44→    console.log('\nInitializing .belt directory...');
 45→    initBeltDirectory(resolvedDir);
 46→    createProgressFile(resolvedDir);
 47→    createFeaturesFile(resolvedDir);
 48→  }
 49→
 50→  // Create session configuration
 51→  const sessionConfig: BrainstormSessionConfig = {
 52→    interactive: options.interactive ?? true,
 53→    ollamaHost: options.ollamaHost,
 54→    projectDir: resolvedDir,
 55→  };
 56→
 57→  // Create and configure session
 58→  const session = createBrainstormSession(sessionConfig);
 59→
 60→  // Set up event listeners for progress feedback
 61→  session.on('phaseStart', phase => {
 62→    const phaseNames: Record<string, string> = {
 63→      context: '📋 Gathering project context',
 64→      diverge: '🌀 Generating feature ideas (Self-MoA)',
 65→      judge: '⚖️ Evaluating features (LLM-as-Judge)',
 66→      refine: '✨ Refining features (Self-Refine)',
 67→      synthesize: '🔗 Synthesizing backlog',
 68→      review: '👁️ Interactive review',
 69→      complete: '✅ Complete',
 70→    };
 71→    console.log(`\n${phaseNames[phase] || phase}...`);
 72→  });
 73→
 74→  session.on('phaseComplete', (phase, success) => {
 75→    if (success) {
 76→      console.log(`  ✓ ${phase} phase completed`);
 77→    } else {
 78→      console.log(`  ✗ ${phase} phase failed`);
 79→    }
 80→  });
 81→
 82→  session.on('error', (phase, error) => {
 83→    console.error(`\n❌ Error in ${phase} phase: ${error}`);
 84→  });
 85→
 86→  // Check prerequisites unless skipped
 87→  if (!options.skipPrerequisites) {
 88→    console.log('\nChecking prerequisites...');
 89→    const prereqs = await session.checkPrerequisites();
 90→    if (!prereqs.ready) {
 91→      console.error(`\n❌ ${prereqs.error}`);
 92→      console.log('\nTo fix this:');
 93→      console.log('  1. Start Ollama: ollama serve');
 94→      console.log('  2. Pull required model: ollama pull deepseek-r1:8b');
 95→      process.exit(1);
 96→    }
 97→    console.log('  ✓ Ollama is running with required models');
 98→  }
 99→
100→  // Build context from provided data
101→  let context: ProjectContext | undefined;
102→  if (providedContext && providedContext.name && providedContext.description) {
103→    context = {
104→      name: providedContext.name,
105→      description: providedContext.description,
106→      domain: providedContext.domain || 'general',
107→      goals: providedContext.goals || [],
108→      targetUsers: providedContext.targetUsers || [],
109→      techStack: providedContext.techStack,
110→      constraints: providedContext.constraints,
111→    };
112→  }
113→
114→  // Run the brainstorming session
115→  console.log('\nStarting brainstorming pipeline...\n');
116→
117→  let backlog: FeatureBacklog | null = null;
118→  try {
119→    backlog = await session.run(context);
120→  } catch (error) {
121→    const message = error instanceof Error ? error.message : String(error);
122→    console.error(`\n❌ Brainstorming failed: ${message}`);
123→    process.exit(1);
124→  } finally {
125→    // Cleanup event listeners to prevent memory leaks
126→    session.destroy();
127→  }
128→
129→  if (backlog) {
130→    console.log('\n' + '═'.repeat(50));
131→    console.log('📦 BRAINSTORMING COMPLETE');
132→    console.log('═'.repeat(50));
133→    console.log(`\nProject: ${backlog.projectName}`);
