162→/**
163→ * Parse CLI arguments for brainstorm command
164→ */
165→export function parseBrainstormArgs(args: string[]): {
166→  projectDir: string;
167→  options: BrainstormOptions;
168→  context?: Partial<ProjectContext>;
169→} {
170→  const projectDir = args.find(arg => !arg.startsWith('--')) || process.cwd();
171→  const options: BrainstormOptions = {};
172→  const context: Partial<ProjectContext> = {};
173→
174→  for (let i = 0; i < args.length; i++) {
175→    const arg = args[i];
176→
177→    if (arg === '--non-interactive' || arg === '-n') {
178→      options.interactive = false;
179→    } else if (arg === '--ollama-host' && args[i + 1]) {
180→      options.ollamaHost = args[++i];
181→    } else if (arg === '--skip-prerequisites') {
182→      options.skipPrerequisites = true;
183→    } else if (arg === '--name' && args[i + 1]) {
184→      context.name = args[++i];
185→    } else if (arg === '--description' && args[i + 1]) {
186→      context.description = args[++i];
187→    } else if (arg === '--domain' && args[i + 1]) {
188→      context.domain = args[++i];
189→    } else if (arg === '--goal' && args[i + 1]) {
190→      context.goals = context.goals || [];
191→      context.goals.push(args[++i]);
192→    }
193→  }
194→
195→  return {
196→    projectDir,
197→    options,
198→    context,
199→  };
200→}
