  1→import { execSync } from "node:child_process";
  2→import {
  3→	chmodSync,
  4→	existsSync,
  5→	mkdirSync,
  6→	unlinkSync,
  7→	writeFileSync,
  8→} from "node:fs";
  9→import { homedir } from "node:os";
 10→import { dirname, join, resolve } from "node:path";
 11→import { fileURLToPath } from "node:url";
 12→import { loadConfig } from "./config.js";
 13→import { CONFIG_DIR } from "./paths.js";
 14→
 15→const PLIST_NAME = "com.user.compliance";
 16→const LAUNCH_AGENTS_DIR = join(homedir(), "Library", "LaunchAgents");
 17→const PLIST_PATH = join(LAUNCH_AGENTS_DIR, `${PLIST_NAME}.plist`);
 18→const WRAPPER_PATH = join(CONFIG_DIR, "Compliance");
 19→
 20→export interface AutostartStatus {
 21→	enabled: boolean;
 22→	loaded: boolean;
 23→	plistPath: string;
 24→}
 25→
 26→function getCliPath(): string {
 27→	const __filename = fileURLToPath(import.meta.url);
 28→	const __dirname = dirname(__filename);
 29→	return resolve(__dirname, "cli.js");
 30→}
 31→
 32→function getNodePath(): string {
 33→	try {
 34→		return execSync("which node", { encoding: "utf-8" }).trim();
 35→	} catch {
 36→		return "/usr/local/bin/node";
 37→	}
 38→}
 39→
 40→function isLaunchAgentLoaded(): boolean {
 41→	try {
 42→		const output = execSync("launchctl list", { encoding: "utf-8" });
 43→		return output.includes(PLIST_NAME);
 44→	} catch {
 45→		return false;
 46→	}
 47→}
 48→
 49→export function getAutostartStatus(): AutostartStatus {
 50→	return {
 51→		enabled: existsSync(PLIST_PATH),
 52→		loaded: isLaunchAgentLoaded(),
 53→		plistPath: PLIST_PATH,
 54→	};
 55→}
 56→
 57→export function isAutostartEnabled(): boolean {
 58→	return existsSync(PLIST_PATH);
 59→}
 60→
 61→function createWrapperScript(): void {
 62→	const cliPath = getCliPath();
 63→	const nodePath = getNodePath();
 64→	const config = loadConfig();
 65→
 66→	const args = ["start"];
 67→	if (config.verbose) args.push("-v");
 68→	args.push("-i", String(config.intervalMs));
 69→	args.push("-p", String(config.movementPx));
 70→	args.push("-t", String(config.idleThresholdMs));
 71→	args.push("-m", config.mode);
 72→
 73→	const script = `#!/bin/bash
 74→exec "${nodePath}" "${cliPath}" ${args.map((a) => `"${a}"`).join(" ")}
 75→`;
 76→
 77→	writeFileSync(WRAPPER_PATH, script, "utf-8");
 78→	chmodSync(WRAPPER_PATH, 0o755);
 79→}
 80→
 81→function generatePlist(): string {
 82→	const programArgs = [`        <string>${WRAPPER_PATH}</string>`].join("\n");
 83→
 84→	return `<?xml version="1.0" encoding="UTF-8"?>
 85→<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
 86→<plist version="1.0">
 87→<dict>
 88→    <key>Label</key>
 89→    <string>${PLIST_NAME}</string>
 90→    <key>ProgramArguments</key>
 91→    <array>
 92→${programArgs}
 93→    </array>
 94→    <key>RunAtLoad</key>
 95→    <true/>
 96→    <key>KeepAlive</key>
 97→    <true/>
 98→    <key>StandardOutPath</key>
 99→    <string>/tmp/compliance.launchd.log</string>
100→    <key>StandardErrorPath</key>
101→    <string>/tmp/compliance.launchd.error.log</string>
102→    <key>ThrottleInterval</key>
103→    <integer>30</integer>
104→</dict>
105→</plist>`;
106→}
107→
108→export function enableAutostart(): { success: boolean; error?: string } {
109→	try {
110→		if (!existsSync(LAUNCH_AGENTS_DIR)) {
111→			mkdirSync(LAUNCH_AGENTS_DIR, { recursive: true });
112→		}
113→
114→		if (!existsSync(CONFIG_DIR)) {
115→			mkdirSync(CONFIG_DIR, { recursive: true });
116→		}
117→
118→		createWrapperScript();
119→
120→		const plistContent = generatePlist();
121→		writeFileSync(PLIST_PATH, plistContent, "utf-8");
122→
123→		try {
124→			execSync(`launchctl unload "${PLIST_PATH}" 2>/dev/null`, {
125→				encoding: "utf-8",
126→			});
127→		} catch {
128→			// Ignore if not loaded
129→		}
130→
131→		execSync(`launchctl load "${PLIST_PATH}"`, { encoding: "utf-8" });
132→
133→		return { success: true };
134→	} catch (err) {
135→		return {
136→			success: false,
137→			error: err instanceof Error ? err.message : String(err),
138→		};
139→	}
140→}
141→
142→export function disableAutostart(): { success: boolean; error?: string } {
143→	try {
144→		if (isLaunchAgentLoaded()) {
145→			try {
146→				execSync(`launchctl unload "${PLIST_PATH}"`, { encoding: "utf-8" });
147→			} catch {
148→				// Ignore unload errors
149→			}
150→		}
151→
152→		if (existsSync(PLIST_PATH)) {
153→			unlinkSync(PLIST_PATH);
154→		}
155→
156→		if (existsSync(WRAPPER_PATH)) {
157→			unlinkSync(WRAPPER_PATH);
158→		}
159→
160→		return { success: true };
161→	} catch (err) {
162→		return {
163→			success: false,
164→			error: err instanceof Error ? err.message : String(err),
165→		};
166→	}
167→}
168→
169→export function formatAutostartStatus(): string {
170→	const status = getAutostartStatus();
171→
172→	if (status.enabled && status.loaded) {
173→		return "Autostart: ✅ Enabled (loaded)";
174→	}
175→	if (status.enabled && !status.loaded) {
176→		return "Autostart: ⚠️  Enabled (not loaded - will start on next login)";
177→	}
178→	return "Autostart: ⏹  Disabled";
179→}
