  9→function runCli(
 10→  args: string[] = [],
 11→  options: SpawnOptionsWithoutStdio = {},
 12→): Promise<{
 13→  stdout: string;
 14→  stderr: string;
 15→  exitCode: number;
 16→}> {
 17→  return new Promise(resolve => {
 18→    const proc = spawn(
 19→      'node',
 20→      [
 21→        CLI_PATH,
 22→        ...args,
 23→      ],
 24→      {
 25→        ...options,
 26→        env: {
 27→          ...process.env,
 28→          ...options.env,
 29→        },
 30→      },
 31→    );
 32→
 33→    let stdout = '';
 34→    let stderr = '';
 35→
 36→    proc.stdout.on('data', data => {
 37→      stdout += data.toString();
 38→    });
 39→
 40→    proc.stderr.on('data', data => {
 41→      stderr += data.toString();
 42→    });
 43→
 44→    proc.on('close', exitCode => {
 45→      resolve({
 46→        stdout,
 47→        stderr,
 48→        exitCode: exitCode ?? 0,
 49→      });
 50→    });
 51→  });
 52→}
