 16→function discoverEntries(srcDir: string): Record<string, string> {
 17→  const entries: Record<string, string> = {};
 18→
 19→  if (!existsSync(srcDir)) {
 20→    return entries;
 21→  }
 22→
 23→  const items = readdirSync(srcDir);
 24→
 25→  for (const item of items) {
 26→    const itemPath = resolve(srcDir, item);
 27→    const stat = statSync(itemPath);
 28→
 29→    if (stat.isFile() && item.endsWith('.ts') && !item.endsWith('.d.ts')) {
 30→      const name = basename(item, '.ts');
 31→      entries[name] = itemPath;
 32→    } else if (stat.isDirectory()) {
 33→      const indexPath = resolve(itemPath, 'index.ts');
 34→      if (existsSync(indexPath)) {
 35→        entries[item] = indexPath;
 36→      }
 37→    }
 38→  }
 39→
 40→  return entries;
 41→}
 42→
 43→function generateExports(
 44→  entries: Record<string, string>,
 45→): Record<string, unknown> {
 46→  const exports: Record<string, unknown> = {};
 47→
 48→  for (const name of Object.keys(entries)) {
 49→    const subpath = name === 'index' ? '.' : `./${name}`;
 50→    exports[subpath] = {
 51→      types: `./dist/${name}.d.ts`,
 52→      import: `./dist/${name}.mjs`,
 53→      require: `./dist/${name}.cjs`,
 54→    };
 55→  }
 56→
 57→  return exports;
 58→}
 59→
 60→function updatePackageJson(
 61→  entries: Record<string, string>,
 62→  pkgPath: string,
 63→): void {
 64→  const pkg = JSON.parse(readFileSync(pkgPath, 'utf-8'));
 65→
 66→  pkg.type = 'module';
 67→  pkg.sideEffects = false;
 68→  pkg.main = './dist/index.cjs';
 69→  pkg.module = './dist/index.mjs';
 70→  pkg.types = './dist/index.d.ts';
 71→  pkg.exports = generateExports(entries);
 72→  pkg.files = ['dist'];
 73→
 74→  writeFileSync(pkgPath, JSON.stringify(pkg, null, 2));
 75→
 76→  try {
 77→    execSync(`bunx prettier --write "${pkgPath}"`, { stdio: 'inherit' });
 78→  } catch {
 79→    console.warn('Prettier not available, skipping format');
 80→  }
 81→}
 82→
 83→export default defineConfig(() => {
 84→  const srcDir = resolve(__dirname, 'src');
 85→  const pkgPath = resolve(__dirname, 'package.json');
 86→  const entries = discoverEntries(srcDir);
 87→
 88→  updatePackageJson(entries, pkgPath);
 89→
 90→  console.log('Discovered entries:', Object.keys(entries));
 91→
