103→          return `${entryName}.${ext}`;
104→        },
105→      },
106→      sourcemap: true,
107→      minify: 'terser',
108→    },
109→    plugins: [
110→      externalizeDeps(),
111→      dts({
112→        rollupTypes: false,
113→        tsconfigPath: 'tsconfig.prod.json',
114→      }),
115→      {
116→        enforce: 'pre',
117→        ...nodeExternals(),
