 72→      prompt: `Task: ${task}`,
 73→      temperature: 0.1,
 74→      numPredict: 200,
 75→    });
 76→
 77→    if (!response) {
 78→      return this.defaultRouting(task);
 79→    }
 80→
 81→    try {
 82→      const parsed = JSON.parse(response.response.trim()) as {
 83→        category: string;
 84→        confidence: number;
 85→        reasoning: string;
 86→      };
 87→
 88→      const category = this.normalizeCategory(parsed.category);
 89→      const model = this.getModelForCategory(category);
 90→
 91→      return {
 92→        category,
 93→        model,
 94→        confidence: Math.min(1, Math.max(0, parsed.confidence || 0.5)),
