 93→/**
 94→ * Calculate exponential backoff with jitter
 95→ */
 96→function calculateBackoff(
 97→  attempt: number,
 98→  baseDelayMs: number,
 99→  maxDelayMs: number,
100→  jitterFactor: number
101→): number {
102→  // Exponential: 2^attempt * baseDelay
103→  const exponentialDelay = Math.pow(2, attempt) * baseDelayMs;
104→
105→  // Cap to max
106→  const cappedDelay = Math.min(exponentialDelay, maxDelayMs);
107→
108→  // Add jitter: delay * (1 - jitter/2 + random * jitter)
109→  const jitter = 1 - jitterFactor / 2 + Math.random() * jitterFactor;
110→
111→  return Math.floor(cappedDelay * jitter);
112→}
