 93→function mergeHooks(
 94→  existing: Record<string, MatcherEntry[]> = {},
 95→  required: Record<string, MatcherEntry[]> = {},
 96→): Record<string, MatcherEntry[]> {
 97→  const merged = { ...existing };
 98→
 99→  for (const [hookName, requiredMatchers] of Object.entries(required)) {
100→    if (!merged[hookName]) {
101→      merged[hookName] = [];
102→    }
103→
104→    for (const requiredMatcher of requiredMatchers) {
105→      const existingMatcher = merged[hookName].find(
106→        m => m.matcher === requiredMatcher.matcher,
107→      );
108→
109→      if (existingMatcher) {
110→        for (const hook of requiredMatcher.hooks) {
111→          const hookExists = existingMatcher.hooks.some(
112→            h => h.command === hook.command,
113→          );
114→          if (!hookExists) {
115→            existingMatcher.hooks.push(hook);
116→          }
117→        }
118→      } else {
119→        merged[hookName].push(requiredMatcher);
120→      }
121→    }
122→  }
123→
124→  return merged;
125→}
