140→  }
141→
142→  // Create or update settings.json
143→  let settings: ClaudeSettings = {
144→    $schema: 'https://json.schemastore.org/claude-code-settings.json',
145→    hooks: {},
146→  };
147→
148→  if (existsSync(settingsPath)) {
