 56→        data: { id: "", connectedAt: 0 },
 57→      });
 58→      if (!upgraded) {
 59→        return new Response("WebSocket upgrade failed", { status: 400 });
 60→      }
 61→      return undefined;
 62→    }
 63→
 64→    // ============ SESSIONS API ============
 65→    if (url.pathname === "/api/sessions") {
 66→      if (req.method === "GET") {
 67→        const status = url.searchParams.get("status") as "active" | "archived" | null;
 68→        const sessions = db.listSessions(status ?? undefined);
 69→        return jsonResponse(sessions);
 70→      }
 71→
 72→      if (req.method === "POST") {
 73→        const body = await parseBody<{ name: string; workingDirectory: string }>(req);
 74→        const session = db.createSession(body.name, body.workingDirectory || "/");
 75→        return jsonResponse(session, 201);
 76→      }
 77→    }
 78→
 79→    const sessionMatch = url.pathname.match(/^\/api\/sessions\/([^/]+)$/);
 80→    if (sessionMatch) {
 81→      const sessionId = sessionMatch[1];
 82→
 83→      if (req.method === "GET") {
 84→        const session = db.getSession(sessionId);
 85→        if (!session) return jsonResponse({ error: "Session not found" }, 404);
 86→        return jsonResponse(session);
 87→      }
 88→
 89→      if (req.method === "PATCH") {
 90→        const body = await parseBody<{ claudeSessionId?: string; status?: "archived" }>(req);
 91→        if (body.claudeSessionId) {
 92→          db.updateSessionClaudeId(sessionId, body.claudeSessionId);
