105→    }
106→
107→    // ============ MESSAGES API ============
108→    const messagesMatch = url.pathname.match(/^\/api\/sessions\/([^/]+)\/messages$/);
109→    if (messagesMatch) {
110→      const sessionId = messagesMatch[1];
111→
112→      if (req.method === "GET") {
113→        const limit = url.searchParams.get("limit");
114→        const messages = db.getMessages(sessionId, limit ? parseInt(limit) : undefined);
