125→        return jsonResponse(message, 201);
126→      }
127→    }
128→
129→    const messageMatch = url.pathname.match(/^\/api\/messages\/([^/]+)$/);
130→    if (messageMatch) {
131→      const messageId = messageMatch[1];
132→
133→      if (req.method === "GET") {
134→        const message = db.getMessage(messageId);
135→        if (!message) return jsonResponse({ error: "Message not found" }, 404);
136→        return jsonResponse(message);
137→      }
138→
139→      if (req.method === "PATCH") {
140→        const body = await parseBody<{ content?: string; metadata?: Record<string, unknown> }>(req);
141→        if (body.content !== undefined) {
