 59→export async function handleWebSocketMessage(ws: WS, rawMessage: string | Buffer) {
 60→  const messageStr = typeof rawMessage === "string" ? rawMessage : rawMessage.toString();
 61→
 62→  let parsed: unknown;
 63→  try {
 64→    parsed = JSON.parse(messageStr);
 65→  } catch {
 66→    send(ws, { type: "stream_error", error: "Invalid JSON" });
 67→    return;
 68→  }
 69→
 70→  const message = parsed as { type: string };
 71→
 72→  if (message.type === "ping") {
 73→    ws.send(JSON.stringify({ type: "pong" }));
 74→    return;
 75→  }
 76→
 77→  if (message.type === "send_message") {
 78→    await handleSendMessage(ws, parsed as SendMessageRequest);
 79→  }
 80→}
