312→  updateReminder(
313→    id: string,
314→    updates: Partial<
315→      Pick<Reminder, "content" | "persistent" | "active" | "priority" | "triggerCondition">
316→    >,
317→  ): void {
318→    const setClauses: string[] = [];
319→    const values: (string | number | null)[] = [];
320→
321→    if (updates.content !== undefined) {
322→      setClauses.push("content = ?");
323→      values.push(updates.content);
324→    }
325→    if (updates.persistent !== undefined) {
326→      setClauses.push("persistent = ?");
327→      values.push(updates.persistent ? 1 : 0);
328→    }
329→    if (updates.active !== undefined) {
330→      setClauses.push("active = ?");
331→      values.push(updates.active ? 1 : 0);
332→    }
333→    if (updates.priority !== undefined) {
334→      setClauses.push("priority = ?");
335→      values.push(updates.priority);
336→    }
337→    if (updates.triggerCondition !== undefined) {
338→      setClauses.push("trigger_condition = ?");
339→      values.push(updates.triggerCondition);
340→    }
341→
342→    if (setClauses.length === 0) return;
343→
344→    values.push(id);
345→    this.db
346→      .prepare(`UPDATE reminders SET ${setClauses.join(", ")} WHERE id = ?`)
347→      .run(...values);
348→  }
