  3→export interface InjectionResult {
  4→  enhancedContent: string;
  5→  injectedReminders: string[];
  6→  hasReminders: boolean;
  7→}
  8→
  9→export function formatReminder(reminder: Reminder): string {
 10→  const prefix = reminder.persistent ? "[PERSISTENT]" : "[ONE-TIME]";
 11→  const priority = reminder.priority > 0 ? ` (priority: ${reminder.priority})` : "";
 12→  return `${prefix}${priority} ${reminder.content}`;
 13→}
 14→
 15→export function formatReminderBlock(reminders: Reminder[]): string {
 16→  if (reminders.length === 0) return "";
 17→
 18→  const sorted = [...reminders].sort((a, b) => b.priority - a.priority);
 19→  const formatted = sorted.map((r) => `- ${formatReminder(r)}`).join("\n");
 20→
 21→  return `<system-reminder>
 22→ACTIVE REMINDERS:
 23→${formatted}
 24→</system-reminder>`;
 25→}
 26→
 27→export function injectReminders(
 28→  content: string,
 29→  reminders: Reminder[],
 30→): InjectionResult {
 31→  const activeReminders = reminders.filter((r) => r.active);
 32→
 33→  if (activeReminders.length === 0) {
 34→    return {
 35→      enhancedContent: content,
 36→      injectedReminders: [],
 37→      hasReminders: false,
 38→    };
 39→  }
 40→
 41→  const reminderBlock = formatReminderBlock(activeReminders);
 42→  const enhancedContent = `${reminderBlock}\n\n${content}`;
 43→
 44→  return {
 45→    enhancedContent,
 46→    injectedReminders: activeReminders.map((r) => r.content),
 47→    hasReminders: true,
 48→  };
 49→}
