  1→import { useState, useEffect, useCallback, useRef } from "react";
  2→import type {
  3→  SessionId,
  4→  MessageId,
  5→  ReminderId,
  6→  Session,
  7→  Message,
  8→  Reminder,
  9→  MessageMetadata,
 10→} from "../lib/types";
 11→
 12→const API_BASE = import.meta.env.PUBLIC_API_URL || "http://localhost:3001";
 13→const WS_URL = import.meta.env.PUBLIC_WS_URL || "ws://localhost:3001/ws";
 14→
 15→interface StreamingState {
 16→  messageId: string | null;
 17→  content: string;
 18→}
 19→
 20→interface ClaudeStreamMessage {
 21→  type: "stream_start" | "stream_chunk" | "stream_complete" | "stream_error" | "pong";
 22→  messageId?: string;
 23→  content?: string;
 24→  metadata?: {
 25→    toolCalls?: string[];
 26→    claudeSessionId?: string;
 27→    cost?: number;
 28→    duration?: number;
 29→  };
 30→  error?: string;
 31→}
 32→
 33→export interface UseChatState {
 34→  sessions: Session[];
 35→  currentSession: Session | null;
 36→  messages: Message[];
 37→  reminders: Reminder[];
 38→  isConnected: boolean;
 39→  isLoading: boolean;
 40→  streamingMessageId: string | null;
 41→  streamingContent: string;
 42→  error: string | null;
 43→}
 44→
 45→export interface UseChatActions {
 46→  createSession: (name: string, cwd: string) => Promise<SessionId>;
 47→  selectSession: (sessionId: SessionId) => void;
 48→  archiveSession: (sessionId: SessionId) => Promise<void>;
 49→  deleteSession: (sessionId: SessionId) => Promise<void>;
 50→  sendMessage: (content: string, allowedTools?: string[]) => void;
 51→  addReminder: (content: string, persistent: boolean, priority?: number) => Promise<void>;
 52→  toggleReminder: (id: ReminderId, active: boolean) => Promise<void>;
 53→  deleteReminder: (id: ReminderId) => Promise<void>;
 54→  refreshData: () => Promise<void>;
 55→}
 56→
 57→export type UseChat = UseChatState & UseChatActions;
 58→
 59→export interface UseChatOptions {
 60→  sessionId?: SessionId | null;
 61→}
 62→
 63→async function fetchJson<T>(url: string, options?: RequestInit): Promise<T> {
 64→  const res = await fetch(url, {
 65→    ...options,
 66→    headers: {
 67→      "Content-Type": "application/json",
 68→      ...options?.headers,
 69→    },
 70→  });
 71→  if (!res.ok) {
 72→    throw new Error(`HTTP ${res.status}: ${res.statusText}`);
 73→  }
 74→  return res.json() as Promise<T>;
 75→}
 76→
 77→export function useChat(options: UseChatOptions = {}): UseChat {
 78→  const [selectedSessionId, setSelectedSessionId] = useState<SessionId | null>(
 79→    options.sessionId ?? null
 80→  );
 81→  const [sessions, setSessions] = useState<Session[]>([]);
 82→  const [currentSession, setCurrentSession] = useState<Session | null>(null);
 83→  const [messages, setMessages] = useState<Message[]>([]);
 84→  const [reminders, setReminders] = useState<Reminder[]>([]);
 85→  const [isConnected, setIsConnected] = useState(false);
 86→  const [isLoading, setIsLoading] = useState(false);
 87→  const [streaming, setStreaming] = useState<StreamingState>({
 88→    messageId: null,
 89→    content: "",
 90→  });
 91→  const [error, setError] = useState<string | null>(null);
 92→
 93→  const wsRef = useRef<WebSocket | null>(null);
 94→  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
 95→
 96→  // Track pending message updates
 97→  const pendingUpdatesRef = useRef<
 98→    Map<
 99→      string,
100→      {
101→        messageId: MessageId;
102→        sessionId: SessionId;
103→      }
104→    >
105→  >(new Map());
106→
107→  // Fetch sessions
108→  const fetchSessions = useCallback(async () => {
109→    try {
110→      const data = await fetchJson<Session[]>(`${API_BASE}/api/sessions?status=active`);
111→      setSessions(data);
112→    } catch (e) {
113→      console.error("Failed to fetch sessions:", e);
114→    }
115→  }, []);
116→
117→  // Fetch current session
118→  const fetchCurrentSession = useCallback(async (sessionId: SessionId) => {
119→    try {
120→      const data = await fetchJson<Session>(`${API_BASE}/api/sessions/${sessionId}`);
121→      setCurrentSession(data);
122→    } catch (e) {
123→      console.error("Failed to fetch session:", e);
124→      setCurrentSession(null);
125→    }
126→  }, []);
127→
128→  // Fetch messages
129→  const fetchMessages = useCallback(async (sessionId: SessionId) => {
130→    try {
131→      const data = await fetchJson<Message[]>(`${API_BASE}/api/sessions/${sessionId}/messages`);
132→      setMessages(data);
133→    } catch (e) {
134→      console.error("Failed to fetch messages:", e);
135→    }
136→  }, []);
137→
138→  // Fetch reminders
139→  const fetchReminders = useCallback(async (sessionId?: SessionId) => {
140→    try {
141→      const url = sessionId
142→        ? `${API_BASE}/api/reminders?sessionId=${sessionId}&active=true`
143→        : `${API_BASE}/api/reminders?active=true`;
144→      const data = await fetchJson<Reminder[]>(url);
145→      setReminders(data);
146→    } catch (e) {
147→      console.error("Failed to fetch reminders:", e);
148→    }
149→  }, []);
150→
151→  // Refresh all data
152→  const refreshData = useCallback(async () => {
153→    await fetchSessions();
154→    if (selectedSessionId) {
155→      await Promise.all([
156→        fetchCurrentSession(selectedSessionId),
157→        fetchMessages(selectedSessionId),
158→        fetchReminders(selectedSessionId),
159→      ]);
160→    }
161→  }, [fetchSessions, fetchCurrentSession, fetchMessages, fetchReminders, selectedSessionId]);
162→
163→  // Initial data fetch
164→  useEffect(() => {
165→    fetchSessions();
166→  }, [fetchSessions]);
167→
168→  // Fetch session-specific data when session changes
169→  useEffect(() => {
170→    if (selectedSessionId) {
171→      fetchCurrentSession(selectedSessionId);
172→      fetchMessages(selectedSessionId);
173→      fetchReminders(selectedSessionId);
174→    } else {
175→      setCurrentSession(null);
176→      setMessages([]);
177→      fetchReminders();
178→    }
179→  }, [selectedSessionId, fetchCurrentSession, fetchMessages, fetchReminders]);
180→
181→  // Update message in REST API
182→  const updateMessageContent = useCallback(async (messageId: MessageId, content: string) => {
183→    await fetchJson(`${API_BASE}/api/messages/${messageId}`, {
184→      method: "PATCH",
185→      body: JSON.stringify({ content }),
186→    });
187→  }, []);
188→
189→  const updateMessageMetadata = useCallback(
190→    async (messageId: MessageId, metadata: MessageMetadata) => {
191→      await fetchJson(`${API_BASE}/api/messages/${messageId}`, {
192→        method: "PATCH",
193→        body: JSON.stringify({ metadata }),
194→      });
195→    },
196→    []
197→  );
198→
199→  const updateSessionClaudeId = useCallback(
200→    async (sessionId: SessionId, claudeSessionId: string) => {
201→      await fetchJson(`${API_BASE}/api/sessions/${sessionId}`, {
202→        method: "PATCH",
203→        body: JSON.stringify({ claudeSessionId }),
204→      });
205→    },
206→    []
207→  );
208→
209→  // WebSocket message handler
210→  const handleWsMessage = useCallback(
211→    async (event: MessageEvent) => {
212→      try {
213→        const message = JSON.parse(event.data) as ClaudeStreamMessage;
214→
215→        switch (message.type) {
216→          case "stream_start":
217→            setIsLoading(true);
218→            setStreaming({ messageId: message.messageId ?? null, content: "" });
219→            break;
220→
221→          case "stream_chunk":
222→            if (message.content) {
223→              setStreaming((prev) => ({
224→                ...prev,
225→                content: prev.content + message.content,
226→              }));
227→            }
228→            break;
229→
230→          case "stream_complete": {
231→            setIsLoading(false);
232→            setStreaming({ messageId: null, content: "" });
233→
234→            // Update message content in REST API
235→            if (message.messageId && message.content) {
236→              const pending = pendingUpdatesRef.current.get(message.messageId);
237→              if (pending) {
238→                await updateMessageContent(pending.messageId, message.content);
239→
240→                if (message.metadata) {
241→                  await updateMessageMetadata(pending.messageId, {
242→                    toolCalls: message.metadata.toolCalls,
243→                    claudeSessionId: message.metadata.claudeSessionId,
244→                    cost: message.metadata.cost,
245→                    duration: message.metadata.duration,
246→                  });
247→
248→                  // Update Claude session ID if new
249→                  if (message.metadata.claudeSessionId) {
250→                    await updateSessionClaudeId(
251→                      pending.sessionId,
252→                      message.metadata.claudeSessionId
253→                    );
254→                  }
255→                }
256→
257→                pendingUpdatesRef.current.delete(message.messageId);
258→
259→                // Refresh messages to show updated content
260→                if (selectedSessionId) {
261→                  await fetchMessages(selectedSessionId);
262→                }
263→              }
264→            }
265→            break;
266→          }
267→
268→          case "stream_error":
269→            setIsLoading(false);
270→            setStreaming({ messageId: null, content: "" });
271→            setError(message.error ?? "Unknown streaming error");
272→            break;
273→
274→          case "pong":
275→            // Connection alive
276→            break;
277→        }
278→      } catch (e) {
279→        console.error("Failed to parse WebSocket message:", e);
280→      }
281→    },
282→    [
283→      updateMessageContent,
284→      updateMessageMetadata,
285→      updateSessionClaudeId,
286→      fetchMessages,
287→      selectedSessionId,
288→    ]
289→  );
290→
291→  // WebSocket connection
292→  const connect = useCallback(() => {
293→    if (wsRef.current?.readyState === WebSocket.OPEN) return;
294→
295→    const ws = new WebSocket(WS_URL);
296→
297→    ws.onopen = () => {
298→      setIsConnected(true);
299→      setError(null);
300→    };
301→
302→    ws.onclose = () => {
303→      setIsConnected(false);
304→      reconnectTimeoutRef.current = setTimeout(connect, 2000);
305→    };
306→
307→    ws.onerror = () => {
308→      setError("WebSocket connection error");
309→    };
310→
311→    ws.onmessage = handleWsMessage;
312→
313→    wsRef.current = ws;
314→  }, [handleWsMessage]);
315→
316→  useEffect(() => {
317→    connect();
318→
319→    return () => {
320→      if (reconnectTimeoutRef.current) {
321→        clearTimeout(reconnectTimeoutRef.current);
322→      }
323→      wsRef.current?.close();
324→    };
325→  }, [connect]);
326→
327→  // Send message to WebSocket
328→  const sendWsMessage = useCallback((message: object) => {
329→    if (wsRef.current?.readyState === WebSocket.OPEN) {
330→      wsRef.current.send(JSON.stringify(message));
331→    }
332→  }, []);
333→
334→  // Actions
335→  const createSession = useCallback(async (name: string, cwd: string): Promise<SessionId> => {
336→    const session = await fetchJson<Session>(`${API_BASE}/api/sessions`, {
337→      method: "POST",
