342→    return session.id;
343→  }, [fetchSessions]);
344→
345→  const selectSession = useCallback((sessionId: SessionId) => {
346→    setSelectedSessionId(sessionId);
347→  }, []);
348→
349→  const archiveSession = useCallback(
350→    async (sessionId: SessionId) => {
351→      await fetchJson(`${API_BASE}/api/sessions/${sessionId}`, {
352→        method: "PATCH",
353→        body: JSON.stringify({ status: "archived" }),
354→      });
355→      await fetchSessions();
356→      if (selectedSessionId === sessionId) {
357→        setSelectedSessionId(null);
358→      }
359→    },
360→    [fetchSessions, selectedSessionId]
361→  );
362→
363→  const deleteSession = useCallback(
364→    async (sessionId: SessionId) => {
365→      await fetchJson(`${API_BASE}/api/sessions/${sessionId}`, {
366→        method: "DELETE",
367→      });
368→      await fetchSessions();
369→      if (selectedSessionId === sessionId) {
