376→  const sendMessage = useCallback(
377→    async (content: string, allowedTools?: string[]) => {
378→      if (!selectedSessionId || !currentSession) return;
379→
380→      // Get active reminders for injection
381→      const activeReminders = reminders.filter((r) => r.active);
382→      const reminderContents = activeReminders.map((r) => r.content);
383→
384→      // Create user message
385→      const userMessage = await fetchJson<Message>(
386→        `${API_BASE}/api/sessions/${selectedSessionId}/messages`,
387→        {
388→          method: "POST",
389→          body: JSON.stringify({
390→            role: "user",
391→            content,
392→            metadata:
393→              reminderContents.length > 0 ? { injectedReminders: reminderContents } : undefined,
394→          }),
395→        }
396→      );
397→
398→      // Deactivate non-persistent reminders
399→      for (const reminder of activeReminders) {
400→        if (!reminder.persistent) {
401→          await fetchJson(`${API_BASE}/api/reminders/${reminder.id}`, {
402→            method: "PATCH",
403→            body: JSON.stringify({ active: false }),
404→          });
405→        }
406→      }
407→
408→      // Create placeholder assistant message
409→      const assistantMessage = await fetchJson<Message>(
410→        `${API_BASE}/api/sessions/${selectedSessionId}/messages`,
411→        {
412→          method: "POST",
413→          body: JSON.stringify({
414→            role: "assistant",
415→            content: "",
416→          }),
417→        }
418→      );
419→
420→      // Refresh messages to show user message
421→      await fetchMessages(selectedSessionId);
422→
423→      // Register pending update for when stream completes
424→      const tempMessageId = `${assistantMessage.id}-${Date.now()}`;
425→      pendingUpdatesRef.current.set(tempMessageId, {
426→        messageId: assistantMessage.id,
427→        sessionId: selectedSessionId,
428→      });
429→
430→      // Send to WebSocket for Claude CLI processing
431→      sendWsMessage({
