435→        workingDirectory: currentSession.workingDirectory,
436→        content,
437→        reminderContents,
438→        allowedTools,
439→        messageId: tempMessageId,
440→      });
441→    },
442→    [selectedSessionId, currentSession, reminders, fetchMessages, sendWsMessage]
443→  );
444→
445→  const addReminder = useCallback(
446→    async (content: string, persistent: boolean, priority?: number) => {
447→      await fetchJson(`${API_BASE}/api/reminders`, {
448→        method: "POST",
449→        body: JSON.stringify({
